  "/style/alt-theme/frogies.css": "/* colors and styles derived from https://frogiesarcade.win / discord.gg/unblockedgames */

@import url("https://fonts.googleapis.com/css2?family=Quicksand:wght@500;700&display=swap");
:root {
  --bg: #0e0e0e;
  --secondary-bg: #1a1a1a;
  --third-bg: #080808;
  --fourth-bg: #141414;
  --primary: #00ff9d;
  --secondary: #2a996e;
  --text-color: #ffffff;
  --secondary-text-color: #b8ffcd;
  --button-bg: #1a1a1a;
  --button-hover: #2a996e;
  --gradient-start: #00ff9d;
  --gradient-end: #00ff95;
  --accent: var(--primary);
}

* {
  font-family: "Quicksand", sans-serif !important;
}

button:hover,
.option:hover,
.theme-row:hover,
.active-server:hover,
input[type="button"]:hover,
input[type="submit"]:hover,
input[type="reset"]:hover {
  border-color: var(--primary) !important;
  box-shadow: 0 0 10px var(--primary), 0 0 20px var(--primary),
    0 0 30px var(--primary) !important;
  transition: all 0.2s ease-in-out;
}

.grid-container .card:hover {
  transform: none !important;
  border-color: var(--primary) !important;
  box-shadow: 0 0 10px var(--primary), 0 0 20px var(--primary),
    0 0 30px var(--primary) !important;
  transition: 0.2s ease-in-out;
  z-index: 5;
}

h1,
h2,
.fancy {
  font-weight: 700 !important;
}
",
