  "/style/alt-theme/matrix.css": "@import url("https://fonts.googleapis.com/css2?family=Roboto+Mono:ital,wght@0,100..700;1,100..700&display=swap");

:root {
  --bg: #000000;
  --secondary-bg: #0d0d0d;
  --third-bg: #1a1a1a;
  --fourth-bg: #050505;
  --primary: #00ff41;
  --secondary: #008f11;
  --text-color: #00ff41;
  --secondary-text-color: #003b00;
  --button-bg: #0d0d0d;
  --button-hover: #1a1a1a;
  --gradient-start: #2d7c2d;
  --gradient-end: #00ff40;
  --accent: var(--primary);
}

* {
  font-family: "Roboto Mono" !important;
}

body::before {
  content: " ";
  display: block;
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%),
    linear-gradient(
      90deg,
      rgba(255, 0, 0, 0.06),
      rgba(0, 255, 0, 0.02),
      rgba(0, 0, 255, 0.06)
    );
  z-index: 9999;
  background-size: 100% 2px, 3px 100%;
  pointer-events: none;
}
",
  "/style/alt-theme/vortex.css": "@import url("https://fonts.googleapis.com/css2?family=Chakra+Petch:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400;1,500;1,600;1,700&display=swap");
:root {
  --bg: #000000;
  --secondary-bg: #0d0d0d;
  --third-bg: #1a1a1a;
  --fourth-bg: #050505;
  --primary: #bb00ff;
  --secondary: #bb00ff;
  --text-color: #ffffff;
  --secondary-text-color: #ffffff;
  --button-bg: #0d0d0d;
  --button-hover: #bb00ff;
  --gradient-start: #ffb300;
  --gradient-end: #bb00ff;
  --accent: var(--primary);
}

* {
  font-family: "Chakra Petch" !important;
}

.nav-container,
.v4-text,
strong,
.side-action-btn {
  text-shadow: 0 0 5px #ffffff, 0 0 10px #bb00ff, 0 0 20px #bb00ff;
